import React, { useState, useEffect, useRef } from 'react';
import { User, Ruler, Palette, Camera, Trash2, Save, CheckCircle, ShieldCheck } from 'lucide-react';
import './styles/ProfileSection.css';

const ProfileSection = () => {
  const [formData, setFormData] = useState({
    name: '', height: '', weight: '', skinTone: '',
    chest: 0, waist: 0, hips: 0, fullBodyImage: ''
  });
  const [loading, setLoading] = useState(true);
  const [status, setStatus] = useState({ text: '', type: '' });
  const fileInputRef = useRef(null);

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
  try {
    const token = localStorage.getItem('token');
    const res = await fetch('http://localhost:5000/api/profile', {
      headers: { 
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json' 
      }
    });
    
    const data = await res.json();
    
    if (res.ok) {
      console.log("Profile Data Received:", data); // Check your browser console!
      setFormData({
        name: data.name || '',
        height: data.height || '',
        weight: data.weight || '',
        skinTone: data.skinTone || '',
        chest: data.chest || 0,
        waist: data.waist || 0,
        hips: data.hips || 0,
        fullBodyImage: data.fullBodyImage || ''
      });
    }
  } catch (error) {
    console.error("Fetch error:", error);
  } finally {
    setLoading(false);
  }
};

  const handleInputChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onloadend = () => {
      setFormData({ ...formData, fullBodyImage: reader.result });
    };
  };

  const handleSave = async () => {
    const token = localStorage.getItem('token');
    const res = await fetch('http://localhost:5000/api/profile/update', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
      body: JSON.stringify(formData)
    });
    if (res.ok) {
      setStatus({ text: 'Profile Encrypted & Saved!', type: 'success' });
      setTimeout(() => setStatus({ text: '', type: '' }), 3000);
    }
  };

  if (loading) return <div className="dash-loader">Loading Biometrics...</div>;

  return (
    <div className="profile-container animate-in">
      <header className="profile-header">
        <div className="title-area">
          <h1>Neural <span className="text-gradient">Fit Profile</span></h1>
          <p>Maintain your digital silhouette for 99.9% try-on accuracy.</p>
        </div>
        <button className="save-btn" onClick={handleSave}>
          <Save size={18} /> Save Changes
        </button>
      </header>

      {status.text && <div className={`status-msg ${status.type}`}>{status.text}</div>}

      <div className="profile-grid">
        {/* LEFT: PHOTO SECTION */}
        <div className="profile-card photo-card">
          <div className="card-label"><Camera size={16} /> Virtual Model Photo</div>
          <div className="full-body-preview">
            {formData.fullBodyImage ? (
              <>
                <img src={formData.fullBodyImage} alt="Neural Model" />
                <button className="delete-photo-btn" onClick={() => setFormData({...formData, fullBodyImage: ''})}>
                  <Trash2 size={18} />
                </button>
              </>
            ) : (
              <div className="upload-placeholder" onClick={() => fileInputRef.current.click()}>
                <Camera size={40} />
                <span>Upload Full-Body Photo</span>
                <p>Ensure good lighting and standing pose</p>
              </div>
            )}
            <input type="file" hidden ref={fileInputRef} onChange={handleImageUpload} />
          </div>
          <div className="privacy-hint">
            <ShieldCheck size={14} /> End-to-end encrypted storage active
          </div>
        </div>

        {/* RIGHT: DATA SECTION */}
        <div className="profile-card data-card">
          <div className="card-label"><Ruler size={16} /> Biometric Data</div>
          
          <div className="input-row">
            <div className="input-group">
              <label>Full Name</label>
              <input type="text" name="name" value={formData.name} onChange={handleInputChange} />
            </div>
            <div className="input-group">
              <label>Skin Tone</label>
              <input type="text" name="skinTone" value={formData.skinTone} onChange={handleInputChange} />
            </div>
          </div>

          <div className="measure-grid">
            <div className="measure-item">
              <label>Height (cm)</label>
              <input type="number" name="height" value={formData.height} onChange={handleInputChange} />
            </div>
            <div className="measure-item">
              <label>Weight (kg)</label>
              <input type="number" name="weight" value={formData.weight} onChange={handleInputChange} />
            </div>
            <div className="measure-item highlight-pink">
              <label>Chest (cm)</label>
              <input type="number" name="chest" value={formData.chest} onChange={handleInputChange} />
            </div>
            <div className="measure-item highlight-pink">
              <label>Waist (cm)</label>
              <input type="number" name="waist" value={formData.waist} onChange={handleInputChange} />
            </div>
            <div className="measure-item highlight-pink">
              <label>Hips (cm)</label>
              <input type="number" name="hips" value={formData.hips} onChange={handleInputChange} />
            </div>
          </div>

          <div className="ai-status-box">
             <CheckCircle size={20} className="glow-icon" />
             <div>
                <h4>Body Detection Active</h4>
                <p>AI will use these numbers to warp clothes onto your frame.</p>
             </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProfileSection;
